from typing import List
from functools import lru_cache

class Solution:
    def countValidPatterns(self, L: str) -> int:
        # 统计每个大写字母出现次数
        cnt = [0] * 26
        for ch in L:
            cnt[ord(ch) - ord('A')] += 1

        @lru_cache(None)
        def dfs(state, pre):
            # 如果所有字母都用完，说明得到一种合法排列
            if sum(state) == 0:
                return 1

            ans = 0
            state = list(state)

            # 枚举当前可以放置的字母
            for i in range(26):
                # 剩余数量大于 0，且不能和上一个字母相同
                if state[i] > 0 and i != pre:
                    state[i] -= 1
                    ans += dfs(tuple(state), i)
                    state[i] += 1

            return ans

        # 从初始状态开始DFS搜索
        return dfs(tuple(cnt), -1)
