```java
import java.util.*;

public class Solution {
    private Map<String, Integer> memo = new HashMap<>();

    public int countValidPatterns(String L) {
        // 统计每个大写字母出现次数
        int[] cnt = new int[26];
        for (int i = 0; i < L.length(); i++) {
            cnt[L.charAt(i) - 'A']++;
        }

        // 开始深度优先搜索
        return dfs(cnt, -1);
    }

    private int dfs(int[] cnt, int pre) {
        // 构造记忆化搜索的状态 key
        StringBuilder sb = new StringBuilder();
        sb.append(pre).append('#');
        int left = 0;

        for (int x : cnt) {
            sb.append(x).append(',');
            left += x;
        }

        // 所有字母都放完，找到一种合法排列
        if (left == 0) {
            return 1;
        }

        String key = sb.toString();
        if (memo.containsKey(key)) {
            return memo.get(key);
        }

        int ans = 0;

        // 枚举当前可以放置的字母
        for (int i = 0; i < 26; i++) {
            // 剩余数量大于 0，且不能和上一个字母相同
            if (cnt[i] > 0 && i != pre) {
                cnt[i]--;
                ans += dfs(cnt, i);
                cnt[i]++;
            }
        }

        // 记忆当前状态结果
        memo.put(key, ans);
        return ans;
    }
}
